```typescript
async function handleDnsQuery(domain: string): Promise<string> {
  // Check cache for valid entry
  const cachedRecords = await queryDatabase(`SELECT * FROM dns_cache WHERE domain = '${domain}'`);

  if (cachedRecords.length > 0) {
    const record = cachedRecords[0];
    if (record.expiresAt > Date.now()) {
      return record.ip;
    }
  }

  // Lookup domain in authoritative nameserver
  const response = await fetchFromApi(`https://authoritative.nameserver/lookup?domain=${domain}`);
  const ip = response.ip;
  const ttl = response.ttl || 300;

  // Cache the result with TTL
  await writeToDatabase('dns_cache', {
    domain,
    ip,
    expiresAt: Date.now() + (ttl * 1000)
  });

  return ip;
}
