interface Email {
  from: string;
  subject: string;
  body: string;
}

async function main() {
  const categories = ['urgent', 'newsletter', 'other'];
  const senderCounts: Record<string, number> = {};

  for await (const email of watchEmail({})) {
    const classification = await llmClassify(email.body, categories);

    if (classification === 'urgent') {
      await writeToDatabase('priority_list', email);
    } else if (classification === 'newsletter') {
      await writeToDatabase('weekly_digest', email);
    } else {
      const sender = email.from;
      senderCounts[sender] = (senderCounts[sender] || 0) + 1;
      await logToAudit({ type: 'email_count', sender, count: senderCounts[sender] });
    }
  }
