async function handlePostBuild(config: {
  imageName: string;
  manifestPath: string;
  version: string;
  commitSha: string;
  slackChannel: string;
}) {
  const { imageName, manifestPath, version, commitSha, slackChannel } = config;

  // 1. Push Docker image to registry
  const pushImage = fetchFromApi('https://registry.example.com/push', {
    method: 'POST',
    body: JSON.stringify({ name: imageName, tag: version }),
  });

  // 2. Update deployment manifest in GitOps repo
  const updateManifest = (async () => {
    const content = await readFile(manifestPath);
    const updatedContent = content.replace(/image: .*/, `image: ${imageName}:${version}`);
    await writeFile(manifestPath, updatedContent);
    // Simulate committing the change back to the repo via API
    await fetchFromApi('https://gitops.example.com/api/commit', {
      method: 'POST',
      body: JSON.stringify({ path: manifestPath, content: updatedContent }),
    });
  })();

  // 3. Send Slack notification
  const notifyTeam = sendSlackMessage(
    slackChannel,
    `Build completed. Version ${version} is live.`
  );

  // 4. Tag the Git commit
  const tagCommit = fetchFromApi('https://git.example.com/api/tags', {
    method: 'POST',
    body: JSON.stringify({ sha: commitSha, tag: version }),
  });

  // Execute all actions simultaneously
  await Promise.all([pushImage, updateManifest, notifyTeam, tagCommit]);
}
