async function main() {
  const cpuStream = pollSource('http://fleet-metrics/cpu', 5000);
  const memStream = pollSource('http://memory-monitor/pressure', 5000);
  const diskStream = pollSource('http://storage-layer/latency', 5000);

  const healthStream = combineMetrics(cpuStream, memStream, diskStream);

  for await (const index of healthStream) {
    await writeToDatabase('ops_dashboard', {
      timestamp: new Date().toISOString(),
      healthIndex: index
    });
  }
}

async function* combineMetrics(
  cpu: AsyncIterable<any>,
  mem: AsyncIterable<any>,
  disk: AsyncIterable<any>
): AsyncIterable<number> {
  const it1 = cpu[Symbol.asyncIterator]();
  const it2 = mem[Symbol.asyncIterator]();
  const it3 = disk[Symbol.asyncIterator]();

  while (true) {
    const [c, m, d] = await Promise.all([
      it1.next(),
      it2.next(),
      it3.next()
    ]);

    if (c.done || m.done || d.done) break;

    const score = calculateHealthIndex(c.value, m.value, d.value);
    yield score;
  }
}

function calculateHealthIndex(cpu: any, mem: any, disk: any): number {
  const cpuScore = cpu.utilization || 0;
  const memScore = mem.pressure || 0;
  const diskScore = disk.latencyMs ? Math.min(disk.latencyMs, 100) : 0;

  return (cpuScore + memScore + diskScore) / 3;
}
