async function processLoanApplication(application: any) {
  const [creditScore, employmentHistory] = await Promise.all([
    fetchFromApi(`https://api.credit-bureau.com/score/${application.applicantId}`),
    queryDatabase(`SELECT * FROM employment WHERE applicant_id = '${application.applicantId}'`)
  ]);

  const decision = makeUnderwritingDecision(creditScore, employmentHistory);

  await sendEmail(
    application.email,
    `Loan Application Status: ${decision.status}`,
    decision.message
  );
}

function makeUnderwritingDecision(creditScore: any, employmentHistory: any[]) {
  const hasGoodCredit = creditScore.score >= 700;
  const isEmployed = employmentHistory.some((job) => job.isCurrent);

  if (hasGoodCredit && isEmployed) {
    return {
      status: "Approved",
      message: "Congratulations! Your loan application has been approved."
    };
  } else {
    return {
      status: "Denied",
      message: "We regret to inform you that your loan application has been denied."
    };
  }
}
