async function monitorTemperature() {
  const readings: number[] = [];
  const windowSize = 10;
  const threshold = 80;

  const stream = connectWebSocket('wss://api.sensors.local/temperature');

  for await (const data of stream) {
    readings.push(data.value);

    if (readings.length > windowSize) {
      readings.shift();
    }

    const average = calculateAverage(readings);

    if (average > threshold) {
      await sendPushNotification(`Alert: Average temperature is ${average.toFixed(1)}°F`);
    }
  }
}

function calculateAverage(values: number[]): number {
  if (values.length === 0) return 0;
  const sum = values.reduce((acc, val) => acc + val, 0);
  return sum / values.length;
}
