async function getPricingWithFallback(apiUrl: string, cachePath: string): Promise<any> {
  const maxRetries = 3;
  let lastError: any;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      await logToAudit({ action: 'fetch_price', attempt, url: apiUrl, status: 'started' });

      const priceData = await fetchFromApi(apiUrl);

      await logToAudit({ action: 'fetch_price', attempt, url: apiUrl, status: 'success' });
      return priceData;
    } catch (error) {
      lastError = error;
      await logToAudit({ action: 'fetch_price', attempt, url: apiUrl, status: 'failed', error: String(error) });

      if (attempt < maxRetries) {
        const delayMs = Math.pow(2, attempt) * 1000;
        await new Promise(resolve => setTimeout(resolve, delayMs));
      }
    }
  }

  await logToAudit({ action: 'fetch_price', url: apiUrl, status: 'fallback_to_cache' });
  const cachedContent = await readFile(cachePath);
  return JSON.parse(cachedContent);
}
