    "processJob": {
      "type": "effect",
      "fn": "writeToDB",
      "deps": [
        "jobSource"
      ],
      "config": {
        "table": "processed_jobs"
      },
      "meta": {
        "description": "Attempt to process the message (simulated by DB write)"
      }
    },
    "retryProcess": {
      "type": "derived",
      "fn": "retry",
