async function main() {
  const jobQueue = pollSource('https://api.jobqueue.com/stream', 1000);

  for await (const message of jobQueue) {
    let lastError: Error | null = null;
    let success = false;

    // Attempt processing (1 initial + 2 retries)
    for (let attempt = 0; attempt <= 2; attempt++) {
      try {
        await processMessage(message);
        success = true;
        break;
      } catch (err) {
        lastError = err as Error;
      }
    }

    if (!success && lastError) {
      // Move to Dead-Letter Queue
      await writeToDatabase('dead_letter_queue', {
        originalMessage: message,
        errorMessage: lastError.message,
        timestamp: new Date()
      });

      // Alert Ops
      await sendSlackMessage('ops-channel', `Job failed after 2 retries: ${lastError.message}`);
    }
  }
}
