function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

async function handleUserSignup(email: string, name: string) {
  // 1. Validate email format
  if (!isValidEmail(email)) {
    await logToAudit({ event: 'signup_validation_failed', email, reason: 'Invalid format' });
    return;
  }

  // 2. Create database record
  try {
    await writeToDatabase('users', { email, name, createdAt: new Date() });
  } catch (error) {
    await logToAudit({ event: 'user_creation_failed', email, error });
  }

  // 3. Send welcome email
  try {
    const verificationLink = `https://app.example.com/verify?email=${email}`;
    await sendEmail(email, 'Welcome!', `Please verify your email: ${verificationLink}`);
  } catch (error) {
    await logToAudit({ event: 'welcome_email_failed', email, error });
  }

  // 4. Enqueue analytics event
  try {
    await logToAudit({ event: 'user_signed_up', email, timestamp: new Date() });
  } catch (error) {
    await logToAudit({ event: 'analytics_enqueue_failed', email, error });
  }

  // 5. Provision default workspace
  try {
    await writeToDatabase('workspaces', { ownerId: email, name: 'Default Workspace' });
  } catch (error) {
    await logToAudit({ event: 'workspace_provision_failed', email, error });
  }
}
